BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "ActionLogs" (
	"ID"	TEXT NOT NULL,
	"ModuleName"	TEXT,
	"ActionName"	TEXT,
	"ITCode"	TEXT,
	"ActionUrl"	TEXT,
	"ActionTime"	TEXT NOT NULL,
	"Duration"	REAL NOT NULL,
	"Remark"	TEXT,
	"IP"	TEXT,
	"LogType"	INTEGER NOT NULL,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_ActionLogs" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "Bookmarks" (
	"Id"	TEXT NOT NULL,
	"TenantId"	TEXT,
	"Hash"	TEXT NOT NULL,
	"Model"	TEXT NOT NULL,
	"ModelType"	TEXT NOT NULL,
	"ActivityType"	TEXT NOT NULL,
	"ActivityId"	TEXT NOT NULL,
	"WorkflowInstanceId"	TEXT NOT NULL,
	"CorrelationId"	TEXT NOT NULL,
	CONSTRAINT "PK_Bookmarks" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "DataPrivileges" (
	"ID"	TEXT NOT NULL,
	"UserCode"	TEXT,
	"GroupCode"	TEXT,
	"TableName"	TEXT NOT NULL,
	"RelateId"	TEXT,
	"Domain"	TEXT,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_DataPrivileges" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "DeviceConfigs" (
	"ID"	TEXT NOT NULL,
	"CreateBy"	TEXT,
	"CreateTime"	TEXT,
	"DataSide"	INTEGER NOT NULL,
	"Description"	TEXT,
	"DeviceConfigName"	TEXT,
	"DeviceId"	TEXT,
	"EnumInfo"	TEXT,
	"UpdateBy"	TEXT,
	"UpdateTime"	TEXT,
	"Value"	TEXT,
	CONSTRAINT "PK_DeviceConfigs" PRIMARY KEY("ID"),
	CONSTRAINT "FK_DeviceConfigs_Devices_DeviceId" FOREIGN KEY("DeviceId") REFERENCES "Devices"("ID") ON DELETE NO ACTION ON UPDATE NO ACTION
);
CREATE TABLE IF NOT EXISTS "DeviceVariables" (
	"ID"	TEXT NOT NULL,
	"Alias"	TEXT,
	"DataType"	INTEGER NOT NULL,
	"Description"	TEXT,
	"DeviceAddress"	TEXT,
	"DeviceId"	TEXT,
	"EndianType"	INTEGER NOT NULL,
	"Expressions"	TEXT,
	"Index"	INTEGER NOT NULL,
	"IsTrigger"	INTEGER NOT NULL,
	"IsUpload"	INTEGER NOT NULL,
	"Method"	TEXT,
	"Name"	TEXT,
	"ProtectType"	INTEGER NOT NULL,
	CONSTRAINT "PK_DeviceVariables" PRIMARY KEY("ID"),
	CONSTRAINT "FK_DeviceVariables_Devices_DeviceId" FOREIGN KEY("DeviceId") REFERENCES "Devices"("ID") ON DELETE NO ACTION ON UPDATE NO ACTION
);
CREATE TABLE IF NOT EXISTS "Devices" (
	"ID"	TEXT NOT NULL,
	"AutoStart"	INTEGER NOT NULL,
	"CgUpload"	INTEGER NOT NULL,
	"CmdPeriod"	INTEGER NOT NULL,
	"CreateBy"	TEXT,
	"CreateTime"	TEXT,
	"Description"	TEXT,
	"DeviceName"	TEXT,
	"DeviceTypeEnum"	INTEGER NOT NULL,
	"DriverId"	TEXT,
	"EnforcePeriod"	INTEGER NOT NULL,
	"Index"	INTEGER NOT NULL,
	"ParentId"	TEXT,
	"UpdateBy"	TEXT,
	"UpdateTime"	TEXT,
	CONSTRAINT "PK_Devices" PRIMARY KEY("ID"),
	CONSTRAINT "FK_Devices_Drivers_DriverId" FOREIGN KEY("DriverId") REFERENCES "Drivers"("ID") ON DELETE NO ACTION ON UPDATE NO ACTION,
	CONSTRAINT "FK_Devices_Devices_ParentId" FOREIGN KEY("ParentId") REFERENCES "Devices"("ID") ON DELETE NO ACTION ON UPDATE NO ACTION
);
CREATE TABLE IF NOT EXISTS "Drivers" (
	"ID"	TEXT NOT NULL,
	"AssembleName"	TEXT,
	"AuthorizesNum"	INTEGER NOT NULL,
	"CreateBy"	TEXT,
	"CreateTime"	TEXT,
	"DriverName"	TEXT,
	"FileName"	TEXT,
	"UpdateBy"	TEXT,
	"UpdateTime"	TEXT,
	CONSTRAINT "PK_Drivers" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FileAttachments" (
	"ID"	TEXT NOT NULL,
	"FileName"	TEXT NOT NULL,
	"FileExt"	TEXT NOT NULL,
	"Path"	TEXT,
	"Length"	INTEGER NOT NULL,
	"UploadTime"	TEXT NOT NULL,
	"SaveMode"	TEXT,
	"FileData"	BLOB,
	"ExtraInfo"	TEXT,
	"HandlerInfo"	TEXT,
	"TenantCode"	TEXT,
	CONSTRAINT "PK_FileAttachments" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkGroups" (
	"ID"	TEXT NOT NULL,
	"GroupCode"	TEXT NOT NULL,
	"GroupName"	TEXT NOT NULL,
	"GroupRemark"	TEXT,
	"Manager"	TEXT,
	"TenantCode"	TEXT,
	"ParentId"	TEXT,
	CONSTRAINT "PK_FrameworkGroups" PRIMARY KEY("ID"),
	CONSTRAINT "FK_FrameworkGroups_FrameworkGroups_ParentId" FOREIGN KEY("ParentId") REFERENCES "FrameworkGroups"("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkMenus" (
	"ID"	TEXT NOT NULL,
	"PageName"	TEXT NOT NULL,
	"ActionName"	TEXT,
	"ModuleName"	TEXT,
	"FolderOnly"	INTEGER NOT NULL,
	"IsInherit"	INTEGER NOT NULL,
	"ClassName"	TEXT,
	"MethodName"	TEXT,
	"Domain"	TEXT,
	"ShowOnMenu"	INTEGER NOT NULL,
	"IsPublic"	INTEGER NOT NULL,
	"DisplayOrder"	INTEGER NOT NULL,
	"IsInside"	INTEGER NOT NULL,
	"TenantAllowed"	INTEGER,
	"Url"	TEXT,
	"Icon"	TEXT,
	"ParentId"	TEXT,
	CONSTRAINT "PK_FrameworkMenus" PRIMARY KEY("ID"),
	CONSTRAINT "FK_FrameworkMenus_FrameworkMenus_ParentId" FOREIGN KEY("ParentId") REFERENCES "FrameworkMenus"("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkRoles" (
	"ID"	TEXT NOT NULL,
	"RoleCode"	TEXT NOT NULL,
	"RoleName"	TEXT NOT NULL,
	"RoleRemark"	TEXT,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_FrameworkRoles" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkTenants" (
	"ID"	TEXT NOT NULL,
	"TCode"	TEXT NOT NULL,
	"TName"	TEXT NOT NULL,
	"TDb"	TEXT,
	"TDbType"	INTEGER,
	"DbContext"	TEXT,
	"TDomain"	TEXT,
	"TenantCode"	TEXT,
	"EnableSub"	INTEGER NOT NULL,
	"Enabled"	INTEGER NOT NULL,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_FrameworkTenants" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkUserGroups" (
	"ID"	TEXT NOT NULL,
	"UserCode"	TEXT NOT NULL,
	"GroupCode"	TEXT NOT NULL,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_FrameworkUserGroups" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkUserRoles" (
	"ID"	TEXT NOT NULL,
	"UserCode"	TEXT NOT NULL,
	"RoleCode"	TEXT NOT NULL,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_FrameworkUserRoles" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FrameworkUsers" (
	"ID"	TEXT NOT NULL,
	"Email"	TEXT,
	"Gender"	INTEGER,
	"CellPhone"	TEXT,
	"HomePhone"	TEXT,
	"Address"	TEXT,
	"ZipCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	"ITCode"	TEXT NOT NULL,
	"Password"	TEXT NOT NULL,
	"Name"	TEXT NOT NULL,
	"IsValid"	INTEGER NOT NULL,
	"PhotoId"	TEXT,
	"TenantCode"	TEXT,
	CONSTRAINT "PK_FrameworkUsers" PRIMARY KEY("ID"),
	CONSTRAINT "FK_FrameworkUsers_FileAttachments_PhotoId" FOREIGN KEY("PhotoId") REFERENCES "FileAttachments"("ID") ON DELETE RESTRICT
);
CREATE TABLE IF NOT EXISTS "FrameworkWorkflows" (
	"ID"	TEXT NOT NULL,
	"UserCode"	TEXT NOT NULL,
	"Tag"	TEXT,
	"WorkflowName"	TEXT,
	"ModelType"	TEXT,
	"ModelID"	TEXT,
	"Submitter"	TEXT,
	"WorkflowId"	TEXT NOT NULL,
	"ActivityId"	TEXT NOT NULL,
	"TenantCode"	TEXT,
	"StartTime"	TEXT,
	CONSTRAINT "PK_FrameworkWorkflows" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "FunctionPrivileges" (
	"ID"	TEXT NOT NULL,
	"RoleCode"	TEXT,
	"MenuItemId"	TEXT NOT NULL,
	"Allowed"	INTEGER NOT NULL,
	"TenantCode"	TEXT,
	"CreateTime"	TEXT,
	"CreateBy"	TEXT,
	"UpdateTime"	TEXT,
	"UpdateBy"	TEXT,
	CONSTRAINT "PK_FunctionPrivileges" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "RpcLogs" (
	"ID"	TEXT NOT NULL,
	"Description"	TEXT,
	"DeviceId"	TEXT,
	"EndTime"	TEXT NOT NULL,
	"IsSuccess"	INTEGER NOT NULL,
	"Method"	TEXT,
	"Params"	TEXT,
	"RpcSide"	INTEGER NOT NULL,
	"StartTime"	TEXT NOT NULL,
	CONSTRAINT "PK_RpcLogs" PRIMARY KEY("ID"),
	CONSTRAINT "FK_RpcLogs_Devices_DeviceId" FOREIGN KEY("DeviceId") REFERENCES "Devices"("ID") ON DELETE NO ACTION ON UPDATE NO ACTION
);
CREATE TABLE IF NOT EXISTS "SystemConfig" (
	"ID"	TEXT NOT NULL,
	"ClientId"	TEXT,
	"CreateBy"	TEXT,
	"CreateTime"	TEXT,
	"GatewayName"	TEXT,
	"IoTPlatformType"	INTEGER NOT NULL,
	"MqttIp"	TEXT,
	"MqttPort"	INTEGER NOT NULL,
	"MqttUName"	TEXT,
	"MqttUPwd"	TEXT,
	"UpdateBy"	TEXT,
	"UpdateTime"	TEXT,
	CONSTRAINT "PK_SystemConfig" PRIMARY KEY("ID")
);
CREATE TABLE IF NOT EXISTS "Triggers" (
	"Id"	TEXT NOT NULL,
	"TenantId"	TEXT,
	"Hash"	TEXT NOT NULL,
	"Model"	TEXT NOT NULL,
	"ModelType"	TEXT NOT NULL,
	"ActivityType"	TEXT NOT NULL,
	"ActivityId"	TEXT NOT NULL,
	"WorkflowDefinitionId"	TEXT NOT NULL,
	CONSTRAINT "PK_Triggers" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "WorkflowDefinitions" (
	"Id"	TEXT NOT NULL,
	"DefinitionId"	TEXT NOT NULL,
	"TenantId"	TEXT,
	"Name"	TEXT,
	"DisplayName"	TEXT,
	"Description"	TEXT,
	"Version"	INTEGER NOT NULL,
	"IsSingleton"	INTEGER NOT NULL,
	"PersistenceBehavior"	INTEGER NOT NULL,
	"DeleteCompletedInstances"	INTEGER NOT NULL,
	"IsPublished"	INTEGER NOT NULL,
	"IsLatest"	INTEGER NOT NULL,
	"Tag"	TEXT,
	"Data"	TEXT,
	"CreatedAt"	TEXT NOT NULL,
	CONSTRAINT "PK_WorkflowDefinitions" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "WorkflowExecutionLogRecords" (
	"Id"	TEXT NOT NULL,
	"TenantId"	TEXT,
	"WorkflowInstanceId"	TEXT NOT NULL,
	"ActivityType"	TEXT NOT NULL,
	"ActivityId"	TEXT NOT NULL,
	"Timestamp"	TEXT NOT NULL,
	"EventName"	TEXT,
	"Message"	TEXT,
	"Source"	TEXT,
	"Data"	TEXT,
	CONSTRAINT "PK_WorkflowExecutionLogRecords" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "WorkflowInstances" (
	"Id"	TEXT NOT NULL,
	"DefinitionId"	TEXT NOT NULL,
	"TenantId"	TEXT,
	"Version"	INTEGER NOT NULL,
	"WorkflowStatus"	INTEGER NOT NULL,
	"CorrelationId"	TEXT NOT NULL,
	"ContextType"	TEXT,
	"ContextId"	TEXT,
	"Name"	TEXT,
	"CreatedAt"	TEXT NOT NULL,
	"LastExecutedAt"	TEXT,
	"FinishedAt"	TEXT,
	"CancelledAt"	TEXT,
	"FaultedAt"	TEXT,
	"Data"	TEXT,
	"LastExecutedActivityId"	TEXT,
	"DefinitionVersionId"	TEXT NOT NULL,
	CONSTRAINT "PK_WorkflowInstances" PRIMARY KEY("Id")
);
CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
	"MigrationId"	TEXT NOT NULL,
	"ProductVersion"	TEXT NOT NULL,
	CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY("MigrationId")
);
CREATE INDEX IF NOT EXISTS "IX_DeviceConfigs_DeviceConfigName" ON "DeviceConfigs" (
	"DeviceConfigName"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceConfigs_DeviceId" ON "DeviceConfigs" (
	"DeviceId"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceConfigs_Value" ON "DeviceConfigs" (
	"Value"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceVariables_DataType" ON "DeviceVariables" (
	"DataType"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceVariables_DeviceAddress" ON "DeviceVariables" (
	"DeviceAddress"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceVariables_DeviceId" ON "DeviceVariables" (
	"DeviceId"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceVariables_Method" ON "DeviceVariables" (
	"Method"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_DeviceVariables_Name" ON "DeviceVariables" (
	"Name"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_Devices_AutoStart" ON "Devices" (
	"AutoStart"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_Devices_DeviceName" ON "Devices" (
	"DeviceName"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_Devices_DeviceTypeEnum" ON "Devices" (
	"DeviceTypeEnum"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_Devices_DriverId" ON "Devices" (
	"DriverId"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_Devices_ParentId" ON "Devices" (
	"ParentId"	ASC
);
CREATE INDEX IF NOT EXISTS "IX_FrameworkGroups_ParentId" ON "FrameworkGroups" (
	"ParentId"
);
CREATE INDEX IF NOT EXISTS "IX_FrameworkMenus_ParentId" ON "FrameworkMenus" (
	"ParentId"
);
CREATE INDEX IF NOT EXISTS "IX_FrameworkUsers_PhotoId" ON "FrameworkUsers" (
	"PhotoId"
);
CREATE INDEX IF NOT EXISTS "IX_RpcLogs_DeviceId" ON "RpcLogs" (
	"DeviceId"	ASC
);
COMMIT;
